package 실기시험여도현;

public class 문제5 {
	public static void printChars(char[] arr) {
		for (char c : arr) {
			System.out.print(c);
		}
	}

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char[] arr = { 'h', 'e', 'l', 'l', 'o', ' ', 'j', 'a', 'v', 'a' };
		printChars(arr);
	}
}
